import os
import json
from config import client, API_MODEL
from tools import tools, function_map
from session_manager import SessionManager
from response_handler import process_stream

# ================== Main Program ==================
def main():
    session = SessionManager()
    print(f"?? Code Agent (PowerShell) started. Current directory: {os.getcwd()}")
    print("Type '/help' to see available commands.")

    while True:
        try:
            user_input = input("\nYou: ").strip()
        except EOFError:
            print()
            break

        if not user_input:
            continue

        # ---------- Handle Commands ----------
        if user_input.startswith("/"):
            parts = user_input.split()
            cmd = parts[0].lower()

            if cmd in ["/exit", "/quit"]:
                session.save_current()
                print("Goodbye!")
                break

            elif cmd == "/sessions":
                if len(parts) > 1:
                    try:
                        num = int(parts[1])
                        sessions = session.get_session_files()
                        if 1 <= num <= len(sessions):
                            _, file_path, _, _ = sessions[num-1]
                            session.load_session(file_path)
                        else:
                            print(f"? Invalid number, valid range: 1 ~ {len(sessions)}")
                    except ValueError:
                        print("? Please provide a number, e.g., /sessions 2")
                else:
                    sessions = session.get_session_files()
                    if not sessions:
                        print("?? No saved sessions.")
                    else:
                        print("?? Saved sessions:")
                        for idx, f, title, updated in sessions:
                            print(f"  {idx}. {title} (Updated: {updated})")
                continue

            elif cmd == "/history":
                history = [m for m in session.messages if m["role"] != "system"]
                if not history:
                    print("?? No conversation history.")
                else:
                    print("\n?? === Full Conversation History ===")
                    for i, msg in enumerate(history, 1):
                        role = msg["role"]
                        content = msg.get("content", "")
                        if role == "user":
                            prefix = f"{i}. ? User"
                        elif role == "assistant":
                            prefix = f"{i}. ? AI"
                        elif role == "tool":
                            prefix = f"{i}. ? Tool"
                        else:
                            prefix = f"{i}. {role}"
                        if len(content) > 500:
                            content = content[:500] + "..."
                        print(f"{prefix}: {content}")
                    print("=====================")
                continue

            elif cmd == "/new":
                session.save_current()
                session._init_new_session()
                print("? Started new session.")
                continue

            elif cmd == "/save":
                session.save_current()
                print(f"? Session saved to {session.session_file.name}")
                continue

            elif cmd == "/help":
                print("Available commands:")
                print("  /sessions          - List all saved sessions")
                print("  /sessions <num>    - Load specific session by number")
                print("  /history           - View full conversation history")
                print("  /new               - Start new session (auto-saves current)")
                print("  /save              - Manually save current session")
                print("  /exit or /quit    - Exit and save current session")
                continue

            else:
                print(f"? Unknown command: {cmd}, type /help for help")
                continue

        # ---------- Normal Conversation ----------
        if len(session.messages) == 1:
            title_candidate = user_input[:10].strip()
            session.title = title_candidate if title_candidate else "Untitled Session"

        session.messages.append({"role": "user", "content": user_input})

        while True:
            try:
                stream = client.chat.completions.create(
                    model=API_MODEL,
                    messages=session.messages,
                    tools=tools,
                    tool_choice="auto",
                    stream=True,
                    timeout=60
                )
            except Exception as e:
                print(f"\n? API call failed: {type(e).__name__}: {e}")
                break

            assistant_content, tool_calls = process_stream(stream)

            assistant_message = {"role": "assistant", "content": assistant_content}
            if tool_calls:
                assistant_message["tool_calls"] = tool_calls
            session.messages.append(assistant_message)

            if not tool_calls:
                break

            for tool_call in tool_calls:
                func_name = tool_call["function"]["name"]
                func_args = json.loads(tool_call["function"]["arguments"])

                if func_name not in function_map:
                    result = f"Error: Unknown tool '{func_name}'"
                else:
                    print(f"\n?? Calling tool {func_name} with args: {func_args}")
                    result = function_map[func_name](**func_args)
                    print(f"?? Tool returned: {result[:200]}{'...' if len(result)>200 else ''}")

                session.messages.append({
                    "role": "tool",
                    "tool_call_id": tool_call["id"],
                    "content": result
                })

            session.save_current()

        session.save_current()

if __name__ == "__main__":
    main()

import json

# ================== Stream Response Handler ==================
def process_stream(stream):
    '''Process streaming response, extract content and tool calls'''
    content = ""
    tool_calls_dict = {}

    for chunk in stream:
        if not chunk.choices:
            continue
        delta = chunk.choices[0].delta

        if delta.content:
            print(delta.content, end="", flush=True)
            content += delta.content

        if delta.tool_calls:
            for tc in delta.tool_calls:
                idx = tc.index
                if idx not in tool_calls_dict:
                    tool_calls_dict[idx] = {"id": None, "name": None, "arguments": ""}
                if tc.id:
                    tool_calls_dict[idx]["id"] = tc.id
                if tc.function:
                    if tc.function.name:
                        tool_calls_dict[idx]["name"] = tc.function.name
                    if tc.function.arguments:
                        tool_calls_dict[idx]["arguments"] += tc.function.arguments

    if content:
        print()

    tool_calls = []
    for idx in sorted(tool_calls_dict.keys()):
        item = tool_calls_dict[idx]
        if item["id"] and item["name"]:
            tool_calls.append({
                "id": item["id"],
                "type": "function",
                "function": {
                    "name": item["name"],
                    "arguments": item["arguments"]
                }
            })
    return content, tool_calls

import subprocess
import os

# ================== 工具函数 ==================
def exec_powershell(command: str, timeout: int = 30) -> str:
    '''Execute PowerShell command'''
    try:
        result = subprocess.run(
            ["powershell.exe", "-Command", command],
            capture_output=True,
            text=True,
            timeout=timeout,
            shell=False
        )
        output = result.stdout
        if result.stderr:
            output += "\\n[stderr]\\n" + result.stderr
        return output.strip() or "[Command executed successfully, no output]"
    except subprocess.TimeoutExpired:
        return f"Command timed out after {timeout} seconds: {command}"
    except Exception as e:
        return f"Execution failed: {str(e)}"


# ================== 工具定义 ==================
tools = [
    {
        "type": "function",
        "function": {
            "name": "exec_powershell",
            "description": "Execute a PowerShell command and return the output (including stdout and stderr).",
            "parameters": {
                "type": "object",
                "properties": {
                    "command": {"type": "string", "description": "PowerShell command string, e.g., 'Get-Process'"}
                },
                "required": ["command"]
            }
        }
    }
]

function_map = {
